// Talko launch animation scene — 9:16, 4.5s
// Uses globals from animations.jsx: Stage, Sprite, useTime, useSprite, Easing, interpolate, animate

const { Stage, Sprite, useTime, useSprite, Easing, interpolate, animate, clamp } = window;

const W = 1080, H = 1920, DUR = 4.5;

// The Talko mark: geometric T + speech-bubble tail (matches icon version 1)
function TalkoMark({ size = 400, progress = 1, tailProgress = 1, color = '#fff' }) {
  // progress: 0..1 build-in of the T bars; tailProgress: 0..1 for tail pop
  const stemH = 100 * progress;
  const barW = 140 * progress;
  return (
    <svg viewBox="0 0 240 240" width={size} height={size} style={{ display: 'block', overflow: 'visible' }}>
      <g fill={color}>
        {/* vertical stem grows downward */}
        <rect x="85" y="60" width="70" height={stemH} rx="8" />
        {/* crossbar grows from center */}
        <rect x={120 - barW / 2} y="85" width={barW} height="35" rx="8" />
        {/* tail pops with scale */}
        <g transform={`translate(165,155) scale(${tailProgress}) translate(-165,-155)`}>
          <path d="M 160 145 L 180 165 L 155 160 Z" />
        </g>
      </g>
    </svg>
  );
}

// Scene 1: dark screen, dots pulse in like a typing indicator (0 – 1.2s)
function TypingDots() {
  const { localTime } = useSprite();
  const dots = [0, 1, 2];
  const fadeOut = animate({ from: 1, to: 0, start: 0.9, end: 1.2, ease: Easing.easeInQuad })(localTime);
  return (
    <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 36, opacity: fadeOut }}>
      {dots.map((i) => {
        const t = Math.max(0, localTime - i * 0.15);
        const bounce = Math.abs(Math.sin(t * 5)) * 40;
        const appear = clamp(t * 6, 0, 1);
        return (
          <div key={i} style={{
            width: 56, height: 56, borderRadius: '50%', background: '#fff',
            opacity: appear * 0.9,
            transform: `translateY(${-bounce}px) scale(${appear})`,
          }} />
        );
      })}
    </div>
  );
}

// Scene 2: the mark builds (1.2 – 3.0s)
function MarkBuild() {
  const { localTime } = useSprite();
  const build = animate({ from: 0, to: 1, start: 0, end: 0.6, ease: Easing.easeOutCubic })(localTime);
  const tail = animate({ from: 0, to: 1, start: 0.55, end: 0.85, ease: Easing.easeOutBack })(localTime);
  // subtle settle scale
  const scale = animate({ from: 1.15, to: 1, start: 0, end: 0.8, ease: Easing.easeOutCubic })(localTime);
  return (
    <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ transform: `scale(${scale})` }}>
        <TalkoMark size={520} progress={build} tailProgress={tail} />
      </div>
    </div>
  );
}

// Scene 3: wordmark rises under the mark (2.2 – 4.5s), mark drifts up slightly
function WordmarkScene() {
  const { localTime } = useSprite();
  const rise = animate({ from: 80, to: 0, start: 0, end: 0.6, ease: Easing.easeOutCubic })(localTime);
  const fade = animate({ from: 0, to: 1, start: 0, end: 0.5, ease: Easing.easeOutQuad })(localTime);
  const markUp = animate({ from: 0, to: -90, start: 0, end: 0.6, ease: Easing.easeInOutCubic })(localTime);
  const spacing = animate({ from: 30, to: 14, start: 0, end: 0.8, ease: Easing.easeOutCubic })(localTime);
  // gentle breathing zoom at hold
  const breathe = 1 + Math.sin(localTime * 1.2) * 0.006;
  return (
    <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', transform: `scale(${breathe})` }}>
      <div style={{ transform: `translateY(${markUp}px)` }}>
        <TalkoMark size={520} progress={1} tailProgress={1} />
      </div>
      <div style={{
        marginTop: -20,
        transform: `translateY(${rise + markUp}px)`,
        opacity: fade,
        color: '#fff',
        fontFamily: "'Helvetica Neue', Helvetica, Arial, sans-serif",
        fontWeight: 700,
        fontSize: 110,
        letterSpacing: spacing,
      }}>TALKO</div>
      <div style={{
        transform: `translateY(${rise + markUp}px)`,
        opacity: fade * 0.55,
        marginTop: 18,
        color: '#fff',
        fontFamily: "'Helvetica Neue', Helvetica, Arial, sans-serif",
        fontWeight: 400,
        fontSize: 34,
        letterSpacing: 10,
      }}>SAY IT SIMPLY</div>
    </div>
  );
}

function TalkoSplash() {
  return (
    <Stage width={W} height={H} duration={DUR} background="#000" loop>
      <Sprite start={0} end={1.2}><TypingDots /></Sprite>
      <Sprite start={1.2} end={2.2}><MarkBuild /></Sprite>
      <Sprite start={2.2} end={DUR}><WordmarkScene /></Sprite>
    </Stage>
  );
}

window.TalkoSplash = TalkoSplash;

