/* Talko — monochrome color system. Pure black & white for brand moments,
   toned ink/paper scale for UI. No hue anywhere. */
:root {
  /* Brand absolutes */
  --black: #000000;
  --white: #ffffff;

  /* Ink scale (foregrounds) */
  --ink-0: #0a0a0a;
  --ink-1: #262626;
  --ink-2: #595959;
  --ink-3: #8c8c8c;
  --ink-4: #b3b3b3;

  /* Paper scale (backgrounds) */
  --paper-0: #fafafa;
  --paper-1: #f2f2f2;
  --paper-2: #e6e6e6;
  --paper-3: #d9d9d9;

  /* Semantic aliases */
  --text-primary: var(--ink-0);
  --text-secondary: var(--ink-2);
  --text-tertiary: var(--ink-3);
  --text-inverse: var(--white);

  --surface-page: var(--paper-0);
  --surface-card: var(--white);
  --surface-sunken: var(--paper-1);
  --surface-inverse: var(--ink-0);

  --border-default: var(--paper-2);
  --border-strong: var(--ink-0);

  --action-primary-bg: var(--ink-0);
  --action-primary-fg: var(--white);
  --action-primary-bg-hover: var(--ink-1);

  /* Monochrome "semantic" states — weight, not hue */
  --state-danger-fg: var(--ink-0);
  --state-danger-underline: 2px solid var(--ink-0);
  --state-muted-fg: var(--ink-3);
}

/* Talko type — Helvetica-first, geometric, tight. Two voices:
   DISPLAY (heavy, tight tracking) and LABEL (small caps-style, wide tracking). */
:root {
  --font-sans: "Helvetica Neue", Helvetica, Arial, sans-serif;
  --font-mono: ui-monospace, "SF Mono", "Cascadia Mono", Menlo, monospace;

  /* Display */
  --text-display-xl: 700 64px/1.02 var(--font-sans);
  --text-display: 700 40px/1.08 var(--font-sans);
  --text-title: 700 24px/1.2 var(--font-sans);
  --tracking-display: -0.03em;

  /* Body */
  --text-body-lg: 400 18px/1.5 var(--font-sans);
  --text-body: 400 15px/1.5 var(--font-sans);
  --text-body-sm: 400 13px/1.45 var(--font-sans);

  /* Label (all-caps, wide) */
  --text-label: 700 11px/1.2 var(--font-sans);
  --tracking-label: 0.14em;

  --font-weight-bold: 700;
  --font-weight-regular: 400;
}

/* Talko spacing + radius. 4px base grid. Radii are deliberately split:
   sharp (0) for brand blocks, geometric rounds for UI, pill for actions. */
:root {
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 12px;
  --space-4: 16px;
  --space-5: 24px;
  --space-6: 32px;
  --space-7: 48px;
  --space-8: 64px;

  --radius-none: 0;
  --radius-sm: 8px;
  --radius-md: 16px;
  --radius-lg: 24px;
  --radius-pill: 999px;

  /* App-icon squircle proportion: radius = 23.3% of side */
  --radius-icon-ratio: 0.233;

  --control-height: 48px;
  --control-height-sm: 36px;
  --tap-target-min: 44px;
}

/* Talko effects — monochrome shadows only, used sparingly.
   Motion: fast, springy on entry (ease-out-back), plain ease-out on exit. */
:root {
  --shadow-card: 0 1px 2px rgba(0, 0, 0, 0.06), 0 8px 24px rgba(0, 0, 0, 0.08);
  --shadow-float: 0 12px 48px rgba(0, 0, 0, 0.18);
  --shadow-icon: 0 20px 60px rgba(0, 0, 0, 0.15);

  --ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  --ease-out-back: cubic-bezier(0.34, 1.56, 0.64, 1);
  --dur-fast: 150ms;
  --dur-base: 250ms;
  --dur-slow: 400ms;

  --opacity-hover: 0.85;
  --opacity-disabled: 0.35;
}

/* Minimal resets for design-system consumers. */
body {
  margin: 0;
  font: var(--text-body);
  font-family: var(--font-sans);
  color: var(--text-primary);
  background: var(--surface-page);
  -webkit-font-smoothing: antialiased;
}
