/** Talko Button — black pill primary, outlined secondary, bare ghost. */
export function Button({ variant = "primary", size = "md", disabled = false, icon = null, children, onClick, style }) {
  const h = size === "sm" ? 36 : 48;
  const base = {
    display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 8,
    height: h, padding: size === "sm" ? "0 16px" : "0 24px",
    borderRadius: 999, font: "var(--text-label)", letterSpacing: "var(--tracking-label)",
    textTransform: "uppercase", cursor: disabled ? "default" : "pointer",
    opacity: disabled ? "var(--opacity-disabled)" : 1,
    transition: "opacity var(--dur-fast) var(--ease-out), transform var(--dur-fast) var(--ease-out)",
    border: "none",
  };
  const variants = {
    primary: { background: "var(--action-primary-bg)", color: "var(--action-primary-fg)" },
    secondary: { background: "transparent", color: "var(--ink-0)", border: "2px solid var(--border-strong)" },
    ghost: { background: "transparent", color: "var(--ink-2)" },
  };
  const [pressed, setPressed] = React.useState(false);
  const [hover, setHover] = React.useState(false);
  return (
    <button
      style={{ ...base, ...variants[variant], ...(hover && !disabled ? { opacity: "var(--opacity-hover)" } : {}), ...(pressed ? { transform: "scale(0.97)" } : {}), ...style }}
      disabled={disabled} onClick={onClick}
      onMouseEnter={() => setHover(true)} onMouseLeave={() => { setHover(false); setPressed(false); }}
      onMouseDown={() => setPressed(true)} onMouseUp={() => setPressed(false)}
    >
      {icon}{children}
    </button>
  );
}

