// ds-loader.js — resolves the Talko component namespace.
// Prefers the compiled _ds_bundle.js; falls back to compiling the raw
// component sources with Babel standalone (already on the page).
window.__loadDS = async function (base) {
  if (window.Talko && window.Talko.Button && window.Talko.Dialog) return window.Talko;
  // 1) try the compiled bundle
  try {
    await new Promise((res, rej) => {
      const s = document.createElement("script");
      s.src = base + "_ds_bundle.js";
      s.onload = res; s.onerror = rej;
      document.head.appendChild(s);
    });
    const ns = Object.keys(window).map(k => window[k])
      .find(v => v && typeof v === "object" && v.Button && v.Dialog);
    if (ns) { window.Talko = ns; return ns; }
  } catch (e) { /* bundle not generated yet */ }
  // 2) compile sources directly (dependency order: Button before Dialog)
  const files = [
    "components/forms/Button.jsx",
    "components/forms/IconButton.jsx",
    "components/forms/Input.jsx",
    "components/forms/Select.jsx",
    "components/forms/Checkbox.jsx",
    "components/forms/Radio.jsx",
    "components/forms/Switch.jsx",
    "components/display/Card.jsx",
    "components/display/Badge.jsx",
    "components/display/Tag.jsx",
    "components/display/Tabs.jsx",
    "components/feedback/Dialog.jsx",
    "components/feedback/Toast.jsx",
    "components/feedback/Tooltip.jsx",
  ];
  let src = "";
  for (const f of files) src += (await (await fetch(base + f)).text()) + "\n";
  src = src.replace(/^import .*$/gm, "").replace(/^export /gm, "");
  const names = ["Button","IconButton","Input","Select","Checkbox","Radio","Switch","Card","Badge","Tag","Tabs","Dialog","Toast","Tooltip"];
  const code = Babel.transform(src + "\nreturn {" + names.join(",") + "};", { presets: ["react"] }).code;
